import { describe, it, expect, vi, beforeEach } from 'vitest'

// Mock the supabase client
const mockInsert = vi.fn()
const mockFrom = vi.fn()

const mockSupabase = {
  from: mockFrom,
}

vi.mock('@/lib/supabase/server', () => ({
  createClient: vi.fn(() => Promise.resolve(mockSupabase)),
}))

import { writeTimelineEvent, writeTaskEvent, writeMessageEvent } from '../timeline-writer'
import { createClient } from '@/lib/supabase/server'

const ORG_ID = 'org-123'

function setupInsert(result: { error: { message: string } | null }) {
  mockFrom.mockReturnValue({
    insert: vi.fn().mockResolvedValue(result),
  })
}

beforeEach(() => {
  vi.clearAllMocks()
  setupInsert({ error: null })
})

describe('timeline-writer', () => {
  it('writes task_created event with correct payload', async () => {
    const eventData = { title: 'Buy groceries', priority: 'high' }

    await writeTaskEvent(ORG_ID, 'task-1', 'task_created', eventData)

    expect(mockFrom).toHaveBeenCalledWith('entity_timeline')
    const insertArg = mockFrom.mock.results[0].value.insert.mock.calls[0][0]
    expect(insertArg.org_id).toBe(ORG_ID)
    expect(insertArg.entity_type).toBe('task')
    expect(insertArg.entity_id).toBe('task-1')
    expect(insertArg.event_type).toBe('task_created')
    expect(insertArg.event_data).toEqual(eventData)
  })

  it('writes message_received event with channel_source', async () => {
    await writeMessageEvent(
      ORG_ID,
      'msg-1',
      'message_received',
      { body: 'hello' },
      'whatsapp'
    )

    const insertArg = mockFrom.mock.results[0].value.insert.mock.calls[0][0]
    expect(insertArg.event_type).toBe('message_received')
    expect(insertArg.channel_source).toBe('whatsapp')
    expect(insertArg.entity_type).toBe('channel_message')
  })

  it('sanitizes event_data strings (null bytes, surrogate pairs removed)', async () => {
    const dirtyData = {
      title: 'Hello\u0000World',
      nested: { note: 'Bad\uD800char' },
      count: 42,
    }

    await writeTaskEvent(ORG_ID, 'task-2', 'task_created', dirtyData)

    const insertArg = mockFrom.mock.results[0].value.insert.mock.calls[0][0]
    expect(insertArg.event_data.title).toBe('HelloWorld')
    expect(insertArg.event_data.nested.note).toBe('Badchar')
    expect(insertArg.event_data.count).toBe(42)
  })

  it('returns gracefully when Supabase not configured (null client)', async () => {
    vi.mocked(createClient).mockResolvedValueOnce(null as unknown as ReturnType<typeof createClient>)

    // Should not throw
    await expect(
      writeTimelineEvent({
        orgId: ORG_ID,
        entityType: 'task',
        entityId: 'task-3',
        eventType: 'task_created',
      })
    ).resolves.toBeUndefined()

    expect(mockFrom).not.toHaveBeenCalled()
  })

  it('logs error but never throws on DB failure', async () => {
    setupInsert({ error: { message: 'connection refused' } })
    const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {})

    await expect(
      writeTaskEvent(ORG_ID, 'task-4', 'task_created', { title: 'fail' })
    ).resolves.toBeUndefined()

    expect(consoleSpy).toHaveBeenCalledWith(
      '[timeline-writer] Failed to write timeline event:',
      'connection refused'
    )
    consoleSpy.mockRestore()
  })

  it('uses provided supabaseClient when passed (non-SSR path)', async () => {
    const customClient = {
      from: vi.fn().mockReturnValue({
        insert: vi.fn().mockResolvedValue({ error: null }),
      }),
    }

    await writeTaskEvent(ORG_ID, 'task-5', 'task_created', {}, customClient as never)

    expect(customClient.from).toHaveBeenCalledWith('entity_timeline')
    // Should NOT call createClient when custom client is provided
    expect(createClient).not.toHaveBeenCalled()
  })

  it('falls back to SSR createClient when no client passed', async () => {
    await writeTaskEvent(ORG_ID, 'task-6', 'task_created')

    expect(createClient).toHaveBeenCalled()
    expect(mockFrom).toHaveBeenCalledWith('entity_timeline')
  })
})
